import{_ as e,c as a,o as t,U as i}from"./chunks/framework.9QHaLlVJ.js";const P=JSON.parse('{"title":"probe 探针","description":"","frontmatter":{},"headers":[],"relativePath":"doc/DevOps/Kubernetes/基础/Pod/probe/probe.md","filePath":"packages/doc/src/DevOps/Kubernetes/基础/Pod/probe/probe.md","lastUpdated":1705159462000}'),l={name:"doc/DevOps/Kubernetes/基础/Pod/probe/probe.md"},r=i('<h1 id="probe-探针" tabindex="-1">probe 探针 <a class="header-anchor" href="#probe-探针" aria-label="Permalink to &quot;probe 探针&quot;">​</a></h1><ul><li><a href="./liveProbe">存活探针</a></li><li><a href="./readinessProbe">就绪探针</a></li><li><a href="./startupProbe">启动探针</a></li></ul><h2 id="执行顺序" tabindex="-1">执行顺序 <a class="header-anchor" href="#执行顺序" aria-label="Permalink to &quot;执行顺序&quot;">​</a></h2><p>如果三个探针同时存在，则先执行startupProbe探针，其他两个探针将会被暂时禁用，直到startupProbe一次探测成功，其他2个探针才启动</p><p>如果startupProbe探测失败，kubelet 将杀死容器，并根据restartPolicy重启策略来判断容器是否要进行重启操作。</p><h2 id="区别" tabindex="-1">区别 <a class="header-anchor" href="#区别" aria-label="Permalink to &quot;区别&quot;">​</a></h2><p>就绪探针与存活探针之间的重要区别：如果容器未通过准备检查，则不会被终止或重新启动。</p><p>存活探针：通过杀死异常的容器，并用新的正常容器替代他们来保持Pod正常工作。</p><p>就绪探针：确保只有准备好处理请求的Pod才可以接收探针请求。</p><h2 id="探测机制" tabindex="-1">探测机制 <a class="header-anchor" href="#探测机制" aria-label="Permalink to &quot;探测机制&quot;">​</a></h2><p>大致分为两类，要么使用系统命令，要么程序提供服务，k8s发请求判断。</p><ul><li>HTTP GET探针</li><li>TCP套接字探针</li><li>Exec探针</li></ul><h2 id="配置" tabindex="-1">配置 <a class="header-anchor" href="#配置" aria-label="Permalink to &quot;配置&quot;">​</a></h2><p>三种探测方式配置几乎一样，都是通过httpGet、tcpSocket、exec三种方式进行探测。</p><h3 id="exec" tabindex="-1">exec <a class="header-anchor" href="#exec" aria-label="Permalink to &quot;exec&quot;">​</a></h3><p>在容器内执行指定命令。如果命令退出时返回码为0则认为诊断成功。</p><h3 id="tcpsocket" tabindex="-1">tcpSocket <a class="header-anchor" href="#tcpsocket" aria-label="Permalink to &quot;tcpSocket&quot;">​</a></h3><p>对指定端口上的容器的IP地址进行TCP检查（三次握手）。如果端口打开，则诊断被认为是成功的。</p><h3 id="httpget" tabindex="-1">httpGet <a class="header-anchor" href="#httpget" aria-label="Permalink to &quot;httpGet&quot;">​</a></h3><p>对指定的端口和路径上的容器的IP地址执行HTTPGet请求。如果响应的状态码大于等于200且小于400，则诊断被认为是成功的</p><p>每种检查动作都可能有三种返回状态。</p><ul><li>Success 表示通过了健康检查</li><li>Failure 表示没有通过健康检查</li><li>Unknown 表示检查动作失败</li></ul><h2 id="参数解释" tabindex="-1">参数解释 <a class="header-anchor" href="#参数解释" aria-label="Permalink to &quot;参数解释&quot;">​</a></h2><ul><li><p>initialDelaySeconds 容器启动后第一次检测的延迟时间，单位为秒。 容器启动后第一次检测，在initialDelaySeconds秒之后开始执行。</p></li><li><p>periodSeconds 检测频率, 默认10秒。</p></li><li><p>failureThreshold 当 Pod 启动了并且探测到失败，Kubernetes 的重试次数。 存活探测情况下的放弃就意味着重新启动容器。就绪探测情况下的放弃 Pod 会被打上未就绪的标签。 默认值是 3。最小值是 1</p></li><li><p>timeoutSeconds 探测超时时间，默认1秒。</p></li><li><p>successThreshold</p></li></ul><div class="language-shell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> explain</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deploy.spec.template.spec.containers.startupProbe.successThreshold</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>探测失败后，最少连续探测成功多少次才被认定为成功，默认是1，对于startupProbe，livenessProbe必须是1</p>',26),s=[r];function o(p,n,c,h,d,u){return t(),a("div",null,s)}const k=e(l,[["render",o]]);export{P as __pageData,k as default};
